const telegramData = $input.item.json.body;

// CRITICAL DEBUGGING: Log the entire incoming payload
console.log('=== INCOMING TELEGRAM UPDATE ===' );
console.log('Update ID:', telegramData?.update_id);
console.log('Message ID:', telegramData?.message?.message_id);
console.log('Message Text:', telegramData?.message?.text);
console.log('From User:', telegramData?.message?.from?.username);
console.log('Is Bot:', telegramData?.message?.from?.is_bot);
console.log('Chat ID:', telegramData?.message?.chat?.id);
console.log('Has edited_message:', !!telegramData?.edited_message);
console.log('Has channel_post:', !!telegramData?.channel_post);
console.log('Has callback_query:', !!telegramData?.callback_query);
console.log('Full payload keys:', Object.keys(telegramData));

// CRITICAL FIX: Ignore messages sent by the bot itself AND update messages to prevent infinite loops
const updateId = telegramData?.update_id;
const messageFrom = telegramData?.message?.from;
const hasMessage = telegramData?.message;
const messageText = telegramData?.message?.text || '';

// Block 1: Ignore edited messages, channel posts, callbacks
if (telegramData?.edited_message || telegramData?.channel_post || telegramData?.callback_query) {
  console.log('BLOCKED: Non-message update type');
  return []; // Return empty array to stop workflow without error
}

// Block 2: Ignore if no message object
if (!hasMessage) {
  console.log('BLOCKED: No message object');
  return []; // Return empty array to stop workflow without error
}

// Block 3: Ignore messages from bots
if (!messageFrom || messageFrom.is_bot === true) {
  console.log('BLOCKED: Message from bot or no sender info');
  return []; // Return empty array to stop workflow without error
}

// Block 4: Ignore empty messages (safety check)
if (!messageText && !telegramData?.message?.voice) {
  console.log('BLOCKED: Empty message with no text or voice');
  return []; // Return empty array to stop workflow without error
}

console.log('PASSED ALL CHECKS - Processing message');

const voiceMessage = telegramData?.message?.voice || null;
const chatId = telegramData?.message?.from?.id || '';
const messageId = telegramData?.message?.message_id || '';

// Get current time in Eastern timezone for context
const now = new Date();
const easternTime = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/New_York',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).format(now);

// Determine message type
const isVoice = voiceMessage !== null;
const fileId = voiceMessage?.file_id || null;

return {
  messageText,
  isVoice,
  fileId,
  chatId,
  messageId,
  currentTime: easternTime,
  originalPayload: telegramData
};

// Extract transcribed text and format for next node
const transcribedText = $json.text || '';
const chatId = $('Extract Message').item.json.chatId;
const currentTime = $('Extract Message').item.json.currentTime;

return {
  messageText: transcribedText,
  chatId,
  currentTime,
  isVoice: true,
  originalPayload: $('Extract Message').item.json.originalPayload
};

// Format text message for merging
return {
  messageText: $json.messageText,
  chatId: $json.chatId,
  currentTime: $json.currentTime,
  isVoice: false,
  originalPayload: $json.originalPayload
};

// Detect intent from message text
const messageText = $json.messageText.toLowerCase();

// Intent detection patterns
const queryPatterns = [
  /show.*reminders?/,
  /list.*reminders?/,
  /what.*reminders?/,
  /view.*reminders?/,
  /get.*reminders?/,
  /display.*reminders?/,
  /see.*reminders?/,
  /my reminders?/,
  /upcoming/,
  /today'?s/,
  /this week/,
  /tomorrow'?s/
];

const editPatterns = [
  /edit/,
  /update/,
  /change/,
  /modify/,
  /reschedule/,
  /move.*reminder/,
  /postpone/,
  /adjust/
];

const deletePatterns = [
  /delete/,
  /remove/,
  /cancel/,
  /clear/,
  /erase/,
  /get rid of/
];

let intent = 'create'; // default

if (queryPatterns.some(pattern => pattern.test(messageText))) {
  intent = 'query';
} else if (editPatterns.some(pattern => pattern.test(messageText))) {
  intent = 'edit';
} else if (deletePatterns.some(pattern => pattern.test(messageText))) {
  intent = 'delete';
}

return {
  ...($json),
  intent
};

// Parse and validate Gemini response
try {
  const response = $input.item.json;
  let responseText = '';

  // Handle raw HTTP API response
  if (response.candidates && response.candidates[0]) {
    const content = response.candidates[0].content;
    if (content.parts && content.parts[0]) {
      responseText = content.parts[0].text;
    }
  }

  if (!responseText) {
    throw new Error('No text in Gemini response');
  }

  // Clean up any markdown code blocks if present
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse the JSON
  const parsedTasks = JSON.parse(responseText);

  // Validate structure
  if (!parsedTasks.tasks || !Array.isArray(parsedTasks.tasks)) {
    throw new Error('Invalid JSON structure: missing tasks array');
  }

  if (parsedTasks.tasks.length === 0) {
    throw new Error('No tasks found in response');
  }

  // Validate each task has required fields
  parsedTasks.tasks.forEach((task, index) => {
    if (!task.datetime_iso) {
      throw new Error(`Task ${index + 1} missing datetime_iso`);
    }
    if (!task.title) {
      throw new Error(`Task ${index + 1} missing title`);
    }
    if (!task.reminder_offsets_minutes || !Array.isArray(task.reminder_offsets_minutes)) {
      throw new Error(`Task ${index + 1} missing or invalid reminder_offsets_minutes`);
    }
    // NEW: Validate category
    if (!task.category || typeof task.category !== 'string') {
      throw new Error(`Task ${index + 1} missing or invalid category`);
    }
    // NEW: Validate priority
    const validPriorities = ['high', 'medium', 'low'];
    if (!task.priority || !validPriorities.includes(task.priority)) {
      throw new Error(`Task ${index + 1} missing or invalid priority (must be high/medium/low)`);
    }
  });

  // Return success with parsed tasks
  return {
    success: true,
    tasks: parsedTasks.tasks,
    taskCount: parsedTasks.tasks.length,
    originalMessage: $('Detect Intent').item.json.messageText,
    chatId: $('Detect Intent').item.json.chatId,
    currentTime: $('Detect Intent').item.json.currentTime
  };

} catch (error) {
  // Return error for branching
  return {
    success: false,
    error: error.message,
    originalMessage: $('Detect Intent').item.json.messageText,
    chatId: $('Detect Intent').item.json.chatId,
    geminiRawResponse: JSON.stringify($input.item.json, null, 2)
  };
}

