// Extract enhanced tasks from AI response and prepare for splitting
try {
  const aiResponse = $input.item.json.message || $input.item.json;

  // Clean up response
  let cleanedResponse = aiResponse;
  if (typeof aiResponse === 'string') {
    cleanedResponse = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  }

  // Parse if string, otherwise use as-is
  const enhancedTasks = typeof cleanedResponse === 'string' 
    ? JSON.parse(cleanedResponse) 
    : cleanedResponse;

  // Handle if AI returned object with tasks property or just array
  const tasksArray = Array.isArray(enhancedTasks) 
    ? enhancedTasks 
    : (enhancedTasks.tasks || []);

  if (!Array.isArray(tasksArray) || tasksArray.length === 0) {
    throw new Error('AI did not return valid tasks array');
  }

  // Return with metadata for next nodes
  return {
    tasks: tasksArray,
    chatId: $('Parse & Validate JSON').item.json.chatId,
    taskCount: tasksArray.length
  };

} catch (error) {
  // Fallback to original tasks if AI enhancement fails
  console.error('AI enhancement failed, using original tasks:', error);
  return {
    tasks: $('Parse & Validate JSON').item.json.tasks,
    chatId: $('Parse & Validate JSON').item.json.chatId,
    taskCount: $('Parse & Validate JSON').item.json.taskCount
  };
}

// 1. Target ONLY the new records from the 'Prepare Reminder Records' node
const reminders = $("Prepare Reminder Records").all();
const chatId = reminders[0].json.chatId;
const taskCount = reminders.length;

// 2. Define icons for categories and priorities
const categoryEmoji = { 'homework': '📚', 'gym': '💪', 'personal': '👤', 'work': '💼' };
const priorityEmoji = { 'high': '🔴', 'medium': '🟡', 'low': '🟢' };

// 3. Format each NEW record into a summary line
const summaries = reminders.map(item => {
    const r = item.json;
    const catIcon = categoryEmoji[r.category] || '📌';
    const prioIcon = priorityEmoji[r.priority] || '🟡';

    return `🆔 *ID: ${r.reminderId}* | ${catIcon} *${r.taskTitle}* ${prioIcon}\n   ⏰ ${r.eventTime}\n   🔔 Reminder: ${r.reminderTime}`;
});

// 4. Build the final header and message
const header = taskCount === 1 
    ? `✅ Created 1 new reminder:` 
    : `✅ Created ${taskCount} new reminders:`;

const finalMessage = `${header}\n\n${summaries.join('\n\n')}`;

return {
    chatId,
    message: finalMessage
};

