const messageText = $json.messageText.toLowerCase();
const chatId = $json.chatId;

// Extract time filters
let timeFilter = 'all';
if (/today/i.test(messageText)) {
  timeFilter = 'today';
} else if (/tomorrow/i.test(messageText)) {
  timeFilter = 'tomorrow';
} else if (/this week/i.test(messageText)) {
  timeFilter = 'week';
} else if (/upcoming/i.test(messageText)) {
  timeFilter = 'upcoming';
}

// Extract category filter
let categoryFilter = null;
const categories = ['homework', 'applications', 'gym', 'personal', 'work'];
for (const cat of categories) {
  if (messageText.includes(cat)) {
    categoryFilter = cat;
    break;
  }
}

// Extract priority filter
let priorityFilter = null;
if (/high priority|urgent/i.test(messageText)) {
  priorityFilter = 'high';
} else if (/low priority/i.test(messageText)) {
  priorityFilter = 'low';
} else if (/medium priority/i.test(messageText)) {
  priorityFilter = 'medium';
}

return {
  chatId,
  timeFilter,
  categoryFilter,
  priorityFilter,
  originalMessage: $json.messageText
};

// Filter reminders based on query parameters
const filters = $('Parse Query Request').item.json;
const reminders = $input.all();

const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const todayEnd = new Date(todayStart);
todayEnd.setDate(todayEnd.getDate() + 1);

const tomorrowStart = new Date(todayEnd);
const tomorrowEnd = new Date(tomorrowStart);
tomorrowEnd.setDate(tomorrowEnd.getDate() + 1);

const weekEnd = new Date(todayStart);
weekEnd.setDate(weekEnd.getDate() + 7);

const filtered = reminders.filter(item => {
  const reminder = item.json;
  const eventTime = new Date(reminder.eventTime);

  // Time filter
  if (filters.timeFilter === 'today') {
    if (eventTime < todayStart || eventTime >= todayEnd) return false;
  } else if (filters.timeFilter === 'tomorrow') {
    if (eventTime < tomorrowStart || eventTime >= tomorrowEnd) return false;
  } else if (filters.timeFilter === 'week') {
    if (eventTime < todayStart || eventTime >= weekEnd) return false;
  } else if (filters.timeFilter === 'upcoming') {
    if (eventTime < now) return false;
  }

  // Category filter
  if (filters.categoryFilter && reminder.category !== filters.categoryFilter) {
    return false;
  }

  // Priority filter
  if (filters.priorityFilter && reminder.priority !== filters.priorityFilter) {
    return false;
  }

  return true;
});

return filtered.length > 0 ? filtered : [{ json: { noResults: true } }];

// Format query results for display
const items = $input.all();
const filters = $('Parse Query Request').item.json;

if (items.length === 1 && items[0].json.noResults) {
  return {
    chatId: filters.chatId,
    message: `No reminders found matching your query.`
  };
}

// Group by event
const grouped = {};
items.forEach(item => {
  const r = item.json;
  const key = r.calendarEventId;
  if (!grouped[key]) {
    grouped[key] = {
      title: r.taskTitle,
      description: r.taskDescription,
      category: r.category,
      priority: r.priority,
      eventTime: r.eventTime,
      reminders: []
    };
  }
  grouped[key].reminders.push(r.offsetMinutes);
});

// Format each task
const categoryEmoji = {
  'homework': '📚',
  'applications': '📝',
  'gym': '💪',
  'personal': '👤',
  'work': '💼'
};

const priorityEmoji = {
  'high': '🔴',
  'medium': '🟡',
  'low': '🟢'
};

const formatted = Object.values(grouped).map(task => {
  const eventDate = new Date(task.eventTime);
  const formattedDate = eventDate.toLocaleString('en-US', {
    timeZone: 'America/New_York',
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true
  });

  const catIcon = categoryEmoji[task.category] || '📌';
  const priIcon = priorityEmoji[task.priority] || '🟡';

  const reminderCount = task.reminders.length;
  const reminderText = reminderCount === 1 ? 'reminder' : 'reminders';

  return `${catIcon} *${task.title}* ${priIcon}\n   ⏰ ${formattedDate}\n   🔔 ${reminderCount} ${reminderText}`;
});

const count = formatted.length;
const header = count === 1 ? `Found 1 reminder:` : `Found ${count} reminders:`;

return {
  chatId: filters.chatId,
  message: `${header}\n\n${formatted.join('\n\n')}`
};

// Parse edit request - extract reminder ID and new details
const messageText = $json.messageText;
const chatId = $json.chatId;

// Update line 6 to catch any digit instead of just long timestamps
const idMatch = messageText.match(/\bid\s*(\d+)\b/i) || messageText.match(/\b(\d+)\b/);
const reminderId = idMatch ? idMatch[1] : null;

if (!reminderId) {
  return {
    chatId,
    error: 'Could not find reminder ID. Please specify which reminder to edit.',
    requiresId: true
  };
}

// Detect what to edit
let editType = null;
let newValue = null;

if (/change.*time|reschedule|move.*to/i.test(messageText)) {
  editType = 'time';
  // Extract new time from message (simplified - in production use Gemini)
  newValue = messageText; // Will be parsed by Gemini
} else if (/change.*title|rename/i.test(messageText)) {
  editType = 'title';
  newValue = messageText;
} else if (/change.*category/i.test(messageText)) {
  editType = 'category';
  // Extract category
  const categories = ['homework', 'applications', 'gym', 'personal', 'work'];
  for (const cat of categories) {
    if (messageText.toLowerCase().includes(cat)) {
      newValue = cat;
      break;
    }
  }
} else if (/change.*priority/i.test(messageText)) {
  editType = 'priority';
  if (/high/i.test(messageText)) newValue = 'high';
  else if (/low/i.test(messageText)) newValue = 'low';
  else newValue = 'medium';
}

return {
  chatId,
  reminderId,
  editType,
  newValue,
  originalMessage: messageText
};

// Find the specific reminder by ID
const reminderId = $('Parse Edit Request').item.json.reminderId;
const allReminders = $input.all();

const found = allReminders.filter(item => String(item.json.reminderId) === String(reminderId));

if (found.length === 0) {
  return {
    chatId: $('Parse Edit Request').item.json.chatId,
    error: `Reminder ${reminderId} not found.`,
    notFound: true
  };
}

return found;

// Apply edits based on editType
const editRequest = $('Parse Edit Request').item.json;
const reminder = $json;

// Apply the edit based on type
if (editRequest.editType === 'title') {
  reminder.taskTitle = editRequest.newValue;
} else if (editRequest.editType === 'category') {
  reminder.category = editRequest.newValue;
} else if (editRequest.editType === 'priority') {
  reminder.priority = editRequest.newValue;
} else if (editRequest.editType === 'time') {
  // For time edits, would need to re-parse with Gemini
  // Simplified: just update description
  reminder.taskDescription = `Updated: ${editRequest.newValue}`;
}

return reminder;

// Parse delete request - extract reminder ID or filters
const messageText = $json.messageText;
const chatId = $json.chatId;

// Update line 6 to catch any digit instead of just long timestamps
const idMatch = messageText.match(/\bid\s*(\d+)\b/i) || messageText.match(/\b(\d+)\b/);
const reminderId = idMatch ? idMatch[1] : null;

// Check for "all" deletion
const deleteAll = /delete all|clear all|remove all/i.test(messageText);

// Check for category-specific deletion
let categoryFilter = null;
const categories = ['homework', 'applications', 'gym', 'personal', 'work'];
for (const cat of categories) {
  if (messageText.toLowerCase().includes(cat)) {
    categoryFilter = cat;
    break;
  }
}

return {
  chatId,
  reminderId,
  deleteAll,
  categoryFilter,
  originalMessage: messageText
};

// Filter reminders to delete
const params = $('Parse Delete Request').item.json;
const allReminders = $input.all();

let toDelete = [];

if (params.reminderId) {
  // Delete specific ID
  toDelete = allReminders.filter(item => String(item.json.reminderId) === String(params.reminderId));
} else if (params.deleteAll) {
  // Delete all
  toDelete = allReminders;
} else if (params.categoryFilter) {
  // Delete by category
  toDelete = allReminders.filter(item => item.json.category === params.categoryFilter);
}

if (toDelete.length === 0) {
  return {
    chatId: params.chatId,
    error: 'No reminders found to delete.',
    notFound: true
  };
}

return toDelete;

// Count deleted items
const deleted = $input.all();
const count = deleted.length;

return {
  chatId: $('Parse Delete Request').item.json.chatId,
  message: `✅ Deleted ${count} reminder${count === 1 ? '' : 's'}.`
};

const allTasks = $('Split Tasks').all();
const chatId = $('Extract Enhanced Tasks').item.json.chatId;
const allCalendarEvents = $('Create Calendar Event').all();
const sheetData = $('Get Last ID From Sheet').all(); 
const allReminders = [];

// ID Logic: Finds the highest ID in your sheet, or starts at 0 if empty
let currentId = 0;
if (sheetData.length > 0) {
    const ids = sheetData.map(row => parseInt(row.json.reminderId)).filter(id => !isNaN(id));
    currentId = ids.length > 0 ? Math.max(...ids) : 0;
}

// Helper function for Military Time (MM/DD/YYYY HH:MM) forced to New York Time
const formatMilitaryTime = (date) => {
    return new Date(date).toLocaleString('en-US', {
        timeZone: 'America/New_York', 
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false
    }).replace(',', '');
};

allCalendarEvents.forEach((calEvent, index) => {
    const task = allTasks[index];
    if (!task || !task.json.reminder_offsets_minutes) return;

    task.json.reminder_offsets_minutes.forEach(offsetMinutes => {
        const eventTime = new Date(task.json.datetime_iso);
        const reminderTime = new Date(eventTime.getTime() - (offsetMinutes * 60 * 1000));

        currentId++; 

        allReminders.push({
            json: {
                reminderId: currentId,
                taskTitle: task.json.title,
                taskDescription: task.json.description,
                category: task.json.category || 'personal',
                priority: task.json.priority || 'medium',
                eventTime: formatMilitaryTime(task.json.datetime_iso),
                reminderTime: formatMilitaryTime(reminderTime),
                offsetMinutes: offsetMinutes,
                chatId: chatId,
                calendarEventId: calEvent.json.id,
                sent: false,
                createdAt: formatMilitaryTime(new Date())
            }
        });
    });
});

return allReminders;
